var e=[{id:`L2_1`,type:`dialog`,speaker:`LEESOOYEON_COFFIN_NULL_NULL`,text:{KOREA:`아, 스승님. 잠깐 통신 가능하신가요?`,JPN:`あ、師匠。少し通信可能でしょうか?`,ENG:`Oh, Master. Are you free to talk for a second?`,TWN:`啊，師父，可以佔用您一點時間嗎？`},stage:{bg:`NEWTOWN_NIGHT`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEESOOYEON_COFFIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}},sfx:`FX_CUTSCEN_BEEP`},{id:`L3_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`바쁘다면서? 무슨 일이지?`,JPN:`忙しいと言いながら?何なの?`,ENG:`I thought you were busy. What is it?`,TWN:`不是說我現在很忙嗎？什麼事？`},stage:{bg:`NEWTOWN_NIGHT`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`LEESOOYEON_COFFIN_NULL_NULL`,text:{KOREA:`상황이 급하다 보니 전달하지 못한 사항이 하나 있어서요.`,JPN:`状況が急いでいてみたら伝達することができなかった事項が一つあるからです。`,ENG:`I forgot to inform you something due to the urgent situation.`,TWN:`因為事態緊急，有一件事情之前沒能來得及告訴您。`},stage:{bg:`NEWTOWN_NIGHT`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEESOOYEON_COFFIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`LEESOOYEON_COFFIN_NULL_NULL`,text:{KOREA:`최근 관리국 규정이 강화되면서, 신입사원들은 실전투입에 앞서 대 침식전 의무교육을 받아야 하는 방침이 생겼습니다.`,JPN:`最近管理局規定が強化されて、新入社員は実戦闘口に先立って大侵食前義務教育を受けなければならない方針が生じました。`,ENG:`The Administration's regulations have been tightened recently, and all new employees are required to attend compulsory anti-Corruption training before being deployed to the field.`,TWN:`最近管理局加強了他們的規定，要求新進員工在投入實戰前接受有關侵蝕戰的義務教育。`},stage:{bg:`NEWTOWN_NIGHT`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEESOOYEON_COFFIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`그래서? 그게 나랑 무슨 상관이지?`,JPN:`それで?それが私と何の上官なの?`,ENG:`And? How does that concern me?`,TWN:`所以呢？這跟我有什麼關係？`},stage:{bg:`NEWTOWN_NIGHT`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`LEESOOYEON_COFFIN_NULL_NULL`,text:{KOREA:`그야 스승님처럼 장기휴직 후 복직한 임직원도 교육대상이니까요.`,JPN:`そりゃ師匠のように長期休職後復職した役職員も教育大上ですから。`,ENG:`Well, even executive members like yourself are required to attend training, after an extended leave of absence.`,TWN:`因為像師父這樣經過長期休假後復職的員工也要接受培訓。`},stage:{bg:`NEWTOWN_NIGHT`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEESOOYEON_COFFIN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`진심이냐? 나보고 신입 대상 교육을 받으라고?`,JPN:`本気なのか?私に新入対象教育を受けなさいと?`,ENG:`Are you serious? You want me to take the new employee training?`,TWN:`妳認真？讓我像新人一樣受訓？`},stage:{bg:`NEWTOWN_NIGHT`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`LEESOOYEON_COFFIN_NULL_NULL`,text:{KOREA:`그렇게 대놓고 귀찮다는 티를 내실 필요는 없습니다.`,JPN:`そのようにつけておいて面倒であるというふりをする必要はないです。`,ENG:`You don't have to act like it's that big of an imposition.`,TWN:`請不要這麼不耐煩。`},stage:{bg:`NEWTOWN_NIGHT`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEESOOYEON_COFFIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`LEESOOYEON_COFFIN_NULL_NULL`,text:{KOREA:`스승님이 안 계신 동안 바뀐 것들도 많으니까요.`,JPN:`師匠がおられなかった間変わったものも多いからです。`,ENG:`A lot changed while you were gone, Master.`,TWN:`師父您不在的時候有很多地方都變了。`},stage:{bg:`NEWTOWN_NIGHT`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEESOOYEON_COFFIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`LEESOOYEON_COFFIN_NULL_NULL`,text:{KOREA:`아직 이동 중이실 테니, 일단은 지휘에 도움이 될만한 대 침식전 시뮬레이팅 자료부터 전송해 드리겠습니다.`,JPN:`まだ移動中であるつもりであるから、一段は指揮に助けになるに値する大侵食前シミュルレーティング資料から転送して差し上げます。`,ENG:`Since you're probably on the move, I will transmit some anti-Corruption simulation data that will help you command.`,TWN:`您現在大概還在路上吧，我先把和指揮相關的模擬侵蝕戰資料傳過去。`},stage:{bg:`NEWTOWN_NIGHT`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEESOOYEON_COFFIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};